import { Body, Controller, Post, Put, Req, UseGuards } from '@nestjs/common';
import { ForgotPasswordDto } from './dto/forgot-password.dto';
import { ResetPasswordDto } from './dto/reset-password.dto';
import { LocalAuthGuard } from './guard/local-auth.guard';
import { Public } from '../common/auth-guard.metadata';
import { UsersService } from '../users/users.service';
import { ConfigService } from '@nestjs/config';
import { AuthService } from './auth.service';

@Controller('auth')
export class AuthController {
  constructor(
    private authService: AuthService,
    private userService: UsersService,
    private configService: ConfigService,
  ) {}

  @Public()
  @UseGuards(LocalAuthGuard)
  @Post('login')
  async login(@Req() req: any): Promise<any> {
    return {
      access_token: await this.authService.generateToken(
        {
          username: req.user.username,
          sub: req.user._id,
        },
        this.configService.get<string>('token.access'),
      ),
      user: {
        id: req.user._id,
        username: req.user.username,
      },
    };
  }

  @Public()
  @Post('forgot-password')
  async forgotPassword(@Body() { email }: ForgotPasswordDto): Promise<string> {
    await this.authService.forgotPassword(email);
    return 'Forgot password email sent';
  }

  @Public()
  @Put('reset-password')
  async resetPassword(
    @Body() { token, password }: ResetPasswordDto,
  ): Promise<string> {
    await this.authService.resetPassword(
      token,
      await this.userService.hashPassword(password),
    );
    return 'Reset password success';
  }
}

import {
  Controller,
  Get,
  Post,
  Delete,
  Body,
  Request,
  HttpException,
  HttpStatus,
  Put,
} from '@nestjs/common';

import { RoomsService } from './rooms.service';
import { Room } from './interfaces/room.interface';

@Controller('rooms')
export class RoomsController {
  constructor(private readonly roomsService: RoomsService) {}

  @Get()
  async index(): Promise<Room[]> {
    return await this.roomsService.findAll();
  }

  @Get(':id')
  async show(@Request() req): Promise<Room> {
    const id = req.params.id;
    if (!id)
      throw new HttpException(
        'ID parameter is missing',
        HttpStatus.BAD_REQUEST,
      );

    const room = await this.roomsService.findById(id);
    if (!room)
      throw new HttpException(
        `The room with the id: ${id} does not exists`,
        HttpStatus.BAD_REQUEST,
      );

    return room;
  }

  @Post()
  async create(@Body() body: Room): Promise<Room> {
    if (!body || (body && Object.keys(body).length === 0))
      throw new HttpException('Missing informations', HttpStatus.BAD_REQUEST);

    const room = await this.roomsService.create(body);

    return room;
  }

  @Put(':id')
  async update(@Request() req) {
    const id = req.params.id;
    if (!id)
      throw new HttpException(
        'ID parameter is missing',
        HttpStatus.BAD_REQUEST,
      );

    await this.roomsService.update(id, req.body);
  }

  @Delete(':id')
  public async delete(@Request() req) {
    const id = req.params.id;
    if (!id)
      throw new HttpException(
        'ID parameter is missing',
        HttpStatus.BAD_REQUEST,
      );

    await this.roomsService.delete(id);
  }
}

