function updateTsConfig(
  packageName: string,
  packagePrefix: string,
  root: string,
) {
  return (host: Tree) => {
    if (!host.exists('tsconfig.json')) {
      return host;
    }
    const distRoot = join(root as Path, packageName, 'src');
    const packageKey = packagePrefix
      ? packagePrefix + '/' + packageName
      : packageName;

    return updateJsonFile(
      host,
      'tsconfig.json',
      (tsconfig: TsConfigPartialType) => {
        if (!tsconfig.compilerOptions) {
          tsconfig.compilerOptions = {} as any;
        }
        if (!tsconfig.compilerOptions.baseUrl) {
          tsconfig.compilerOptions.baseUrl = './';
        }
        if (!tsconfig.compilerOptions.paths) {
          tsconfig.compilerOptions.paths = {};
        }
        if (!tsconfig.compilerOptions.paths[packageKey]) {
          tsconfig.compilerOptions.paths[packageKey] = [];
        }
        tsconfig.compilerOptions.paths[packageKey].push(distRoot);

        const deepPackagePath = packageKey + '/*';
        if (!tsconfig.compilerOptions.paths[deepPackagePath]) {
          tsconfig.compilerOptions.paths[deepPackagePath] = [];
        }
        tsconfig.compilerOptions.paths[deepPackagePath].push(distRoot + '/*');

        inPlaceSortByKeys(tsconfig.compilerOptions.paths);
      },
    );
  };
}

private static async createDataSourceFactory(
  options: TypeOrmModuleOptions,
  dataSourceFactory?: TypeOrmDataSourceFactory,
): Promise<DataSource> {
  const dataSourceToken = getDataSourceName(options as DataSourceOptions);
  const createTypeormDataSource =
    dataSourceFactory ??
    ((options: DataSourceOptions) => new DataSource(options));
  return await lastValueFrom(
    defer(async () => {
      let dataSource: DataSource;
      if (!options.autoLoadEntities) {
        dataSource = await createTypeormDataSource(
          options as DataSourceOptions,
        );
      } else {
        let entities = options.entities;
        if (Array.isArray(entities)) {
          entities = entities.concat(
            EntitiesMetadataStorage.getEntitiesByDataSource(dataSourceToken),
          );
        } else {
          entities =
            EntitiesMetadataStorage.getEntitiesByDataSource(dataSourceToken);
        }
        dataSource = await createTypeormDataSource({
          ...options,
          entities,
        } as DataSourceOptions);
      }
      return !dataSource.isInitialized && !options.manualInitialization
        ? dataSource.initialize()
        : dataSource;
    }).pipe(
      handleRetry(
        options.retryAttempts,
        options.retryDelay,
        dataSourceToken,
        options.verboseRetryLog,
        options.toRetry,
      ),
    ),
  );
}

import { dirname, join, normalize, relative } from 'path';
import { Configuration } from '../configuration';
import { getValueOrDefault } from './helpers/get-value-or-default';
import { PluginsLoader } from './plugins/plugins-loader';

export abstract class BaseCompiler<T = Record<string, any>> {
  constructor(private readonly pluginsLoader: PluginsLoader) {}

  public abstract run(
    configuration: Required<Configuration>,
    tsConfigPath: string,
    appName: string | undefined,
    extras?: T,
    onSuccess?: () => void,
  ): any;

  public loadPlugins(
    configuration: Required<Configuration>,
    tsConfigPath: string,
    appName: string | undefined,
  ) {
    const pluginsConfig = getValueOrDefault(
      configuration,
      'compilerOptions.plugins',
      appName,
    );
    const pathToSource = this.getPathToSource(
      configuration,
      tsConfigPath,
      appName,
    );

    const plugins = this.pluginsLoader.load(pluginsConfig, { pathToSource });
    return plugins;
  }

  public getPathToSource(
    configuration: Required<Configuration>,
    tsConfigPath: string,
    appName: string | undefined,
  ) {
    const sourceRoot = getValueOrDefault<string>(
      configuration,
      'sourceRoot',
      appName,
      'sourceRoot',
    );
    const cwd = process.cwd();
    const relativeRootPath = dirname(relative(cwd, tsConfigPath));
    const pathToSource =
      normalize(sourceRoot).indexOf(normalize(relativeRootPath)) >= 0
        ? join(cwd, sourceRoot)
        : join(cwd, relativeRootPath, sourceRoot);

    return pathToSource;
  }
}

import { Transport } from '../enums/transport.enum';
import {
  CustomStrategy,
  KafkaOptions,
  MicroserviceOptions,
  MqttOptions,
  NatsOptions,
  RedisOptions,
  RmqOptions,
  TcpOptions,
} from '../interfaces';
import { ServerGrpc } from './server-grpc';
import { ServerKafka } from './server-kafka';
import { ServerMqtt } from './server-mqtt';
import { ServerNats } from './server-nats';
import { ServerRedis } from './server-redis';
import { ServerRMQ } from './server-rmq';
import { ServerTCP } from './server-tcp';

export class ServerFactory {
  public static create(microserviceOptions: MicroserviceOptions) {
    const { transport, options } = microserviceOptions as Exclude<
      MicroserviceOptions,
      CustomStrategy
    >;
    switch (transport) {
      case Transport.REDIS:
        return new ServerRedis(options as Required<RedisOptions>['options']);
      case Transport.NATS:
        return new ServerNats(options as Required<NatsOptions>['options']);
      case Transport.MQTT:
        return new ServerMqtt(options as Required<MqttOptions>['options']);
      case Transport.GRPC:
        return new ServerGrpc(options);
      case Transport.KAFKA:
        return new ServerKafka(options as Required<KafkaOptions>['options']);
      case Transport.RMQ:
        return new ServerRMQ(options as Required<RmqOptions>['options']);
      default:
        return new ServerTCP(options as Required<TcpOptions>['options']);
    }
  }
}
